#include<bits/stdc++.h>

using namespace std;

const int MAXN = 1e6 + 10;

int n, k;
bool mark[2][MAXN];

int main(){
    ios::sync_with_stdio(false);
    cin.tie(0);
    int te;    cin >> te;
    while (te--){
        cin >> n >> k;
        memset(mark, 0, sizeof(mark));
        for (int i = 0; i < k; i++){
            int x, y; cin >> x >> y, x--, y--;
            mark[0][x] = true;
            mark[1][y] = true;
        }

        cout << n-k << " ";
        int p1 = 0, p2 = 0;
        for (int i = 0; i < n-k; i++){
            while (mark[0][p1]) p1++;
            while (mark[1][p2]) p2++;
            cout << ++p1 << " " << ++p2 << " ";
        }
        cout << "\n";
    }
    return 0;
}

