#include <stdio.h>
#include <string.h>
#include <stdbool.h>

const int MAXN = 1e6 + 10;

int main() {
    int te;
    scanf("%d", &te);
    while (te--) {
        int n, k;
        scanf("%d %d", &n, &k);
        bool mark[2][MAXN];
        memset(mark, 0, sizeof(mark));
        for (int i = 0; i < k; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            mark[0][x - 1] = true;
            mark[1][y - 1] = true;
        }
        printf("%d ", n - k);
        int p1 = 0, p2 = 0;
        for (int i = 0; i < n - k; i++) {
            while (mark[0][p1]) p1++;
            while (mark[1][p2]) p2++;
            printf("%d %d ", p1 + 1, p2 + 1);
            p1++;
            p2++;
        }
        printf("\n");
    }
    return 0;
}

code.Java:
import java.util.*;

public class Main {
    static final int MAXN = (int)1e6 + 10;

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int te = scanner.nextInt();
        while (te-- > 0) {
            int n = scanner.nextInt();
            int k = scanner.nextInt();
            boolean[][] mark = new boolean[2][MAXN];

            for (int i = 0; i < k; i++) {
                int x = scanner.nextInt() - 1;
                int y = scanner.nextInt() - 1;
                mark[0][x] = true;
                mark[1][y] = true;
            }

            System.out.print((n - k) + " ");
            int p1 = 0, p2 = 0;

            for (int i = 0; i < n - k; i++) {
                while (mark[0][p1]) p1++;
                while (mark[1][p2]) p2++;
                System.out.print((p1 + 1) + " " + (p2 + 1) + " ");
                p1++;
                p2++;
            }
            System.out.println();
        }

        scanner.close();
    }
}

