const readline = require('readline');

const MAXN = 1e6 + 10;

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function main() {
    let input = [];

    rl.on('line', (line) => {
        input.push(line.trim());
    });

    rl.on('close', () => {
        let index = 0;
        let te = parseInt(input[index++]);

        while (te--) {
            let [n, k] = input[index++].split(' ').map(Number);
            let mark = Array.from({ length: 2 }, () => Array(MAXN).fill(false));

            for (let i = 0; i < k; i++) {
                let [x, y] = input[index++].split(' ').map(Number);
                mark[0][x - 1] = true;
                mark[1][y - 1] = true;
            }

            process.stdout.write((n - k) + " ");
            let p1 = 0, p2 = 0;

            for (let i = 0; i < n - k; i++) {
                while (mark[0][p1]) p1++;
                while (mark[1][p2]) p2++;
                process.stdout.write((p1 + 1) + " " + (p2 + 1) + " ");
                p1++;
                p2++;
            }
            console.log();
        }
    });
}

